}

const bsrColumnLetter = toColumnLetter(bsrCol);
const items = [];
for (let i = 4; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  const asin = String(row[asinCol] || '').trim();
  if (!sku || /^SKU$/i.test(sku) || /^IMG$/i.test(sku) || /_TOTALS$/i.test(sku)) continue;
  if (!asin || !/^[A-Z0-9]{10}$/i.test(asin)) continue;
  items.push({ json: { rowNumber: i + 1, sku, asin: asin.toUpperCase(), bsrColumnLetter } });
}
return items;

function parseRetryAfterSeconds(value) {
  if (value === null || value === undefined || value === '') return 0;
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
}
function nextBackoffSeconds(previousAttempt, retryAfterSeconds) {
  const capped = Math.min(300, 60 * (2 ** Math.max(1, previousAttempt + 1)));
  const jitter = Math.floor(Math.random() * 31);
  return Math.max(capped + jitter, retryAfterSeconds || 0, 60);
}
const input = $input.first().json || {};
const previousAttempt = Number(input.pollAttempt || 0);
const error = input.error || null;
const rawStatus = String(input.processingStatus || '').toUpperCase();
if (error) {
  const message = String(error.message || input.message || 'Unknown polling error');
  const httpCode = Number(error.httpCode || input.httpCode || 0);
  const retryAfterSeconds = parseRetryAfterSeconds(error.retryAfter || error.headers?.['retry-after'] || error.response?.headers?.['retry-after']);
  if (httpCode === 429 || message.toLowerCase().includes('too many requests') || message.toLowerCase().includes('thrott')) {
    return [{ json: { ...input, processingStatus: 'THROTTLED', pollAttempt: previousAttempt + 1, nextWaitSeconds: nextBackoffSeconds(previousAttempt, retryAfterSeconds) } }];
  }
  throw new Error(message);
}
if (rawStatus === 'FATAL' || rawStatus === 'CANCELLED') {
  throw new Error(`SP report ${rawStatus}: ${input.processingEndTime || input.reportId || 'No report details provided'}`);
}
if (rawStatus === 'DONE') {
  return [{ json: { ...input, processingStatus: 'DONE', pollAttempt: previousAttempt } }];
}
return [{ json: { ...input, processingStatus: rawStatus || 'IN_PROGRESS', pollAttempt: previousAttempt + 1, nextWaitSeconds: nextBackoffSeconds(previousAttempt, 0) } }];

function parseDelimitedLine(line, delimiter) {
  const out = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (ch === delimiter && !inQuotes) {
      out.push(current);
      current = '';
      continue;
    }
    current += ch;
  }
  out.push(current);
  return out.map((value) => String(value || '').trim());
}
function toNumber(input) {
  if (input === null || input === undefined || input === '') return 0;
  const n = Number(String(input).replace(/[\s,$]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
function isMerchantChannel(value) {
  const normalized = String(value || '').trim().toUpperCase();
  if (!normalized) return true;
  if (normalized === 'DEFAULT' || normalized === 'MERCHANT' || normalized === 'MFN') return true;
  return !normalized.includes('AMAZON');
}
let text = String($json.reportText || '').trim();
if (!text) {
  return [{ json: { bySku: {}, skuCount: 0, parseWarning: 'FBM report text empty' } }];
}
if (!text.includes('\n') && text.includes('\\n')) {
  text = text.replace(/\\r\\n/g, '\n').replace(/\\n/g, '\n').replace(/\\t/g, '\t');
}
const lines = text.split(/\r?\n/).filter((line) => line.trim());
if (lines.length < 2) {
  return [{ json: { bySku: {}, skuCount: 0, parseWarning: 'FBM report has no data rows' } }];
}
const delimiter = lines[0].includes('\t') ? '\t' : ',';
const headers = parseDelimitedLine(lines[0], delimiter);
const normalized = headers.map((header) => header.toLowerCase().replace(/[^a-z0-9]/g, ''));
const pickIndex = (candidates) => normalized.findIndex((header) => candidates.includes(header));
const skuIdx = pickIndex(['sellersku', 'sku', 'merchantsku']);
const quantityIdx = pickIndex(['quantity']);
const fulfillmentChannelIdx = pickIndex(['fulfillmentchannel']);
if (skuIdx === -1 || quantityIdx === -1) {
  throw new Error('Could not locate seller-sku and quantity columns in FBM stock report');
}
const bySku = {};
for (let i = 1; i < lines.length; i++) {
  const cols = parseDelimitedLine(lines[i], delimiter);
  const sku = String(cols[skuIdx] || '').trim();
  if (!sku) continue;
  const channel = fulfillmentChannelIdx === -1 ? '' : String(cols[fulfillmentChannelIdx] || '').trim();
  const fbmQuantity = isMerchantChannel(channel) ? toNumber(cols[quantityIdx]) : 0;
  const record = bySku[sku] || { sku, fbaTotalQuantity: 0, fbaFulfillableQuantity: 0, fbaUnsellableQuantity: 0, fbaReservedQuantity: 0, fbmQuantity: 0 };
  record.fbmQuantity = Number((record.fbmQuantity + fbmQuantity).toFixed(2));
  bySku[sku] = record;
}
return [{ json: { bySku, skuCount: Object.keys(bySku).length, parseWarning: null } }];

function toNumber(v) {
  if (v === null || v === undefined) return 0;
  const n = Number(String(v).replace(/[$,%\s,]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const sheet = $('Webhook Read Google Sheet7').first().json || {};
const values = sheet.values || [];
const fbaBySku = $('SP Parse Returns by SKU1').first().json.bySku || {};
const fbmBySku = $('SP Parse FBM Stock by SKU').first().json.bySku || {};
const sheetName = $('Set Credentials').first().json['✅SHEET_NAME'] || 'MOBILITY';

let headerRowIdx = -1;
let skuCol = -1;
for (let i = 0; i < Math.min(values.length, 12); i++) {
  const row = values[i] || [];
  const foundSkuCol = row.findIndex((c) => String(c).trim().toUpperCase() === 'SKU');
  if (foundSkuCol !== -1) {
